mapper.update:
UPDATE project_tasks
SET assigned_to = #{assigned_to, typeHandler=reengineering.ddd.mybatis.support.RefIntegerTypeHandler},
    delegated_by = #{delegated_by, typeHandler=reengineering.ddd.mybatis.support.RefIntegerTypeHandler},
    updated_at = CURRENT_TIMESTAMP
WHERE project_id = #{project_id}
  AND id = #{id}

UPDATE project_tasks
SET delegate_request_id = #{delegate_request_id},
    updated_at = CURRENT_TIMESTAMP
WHERE project_id = #{project_id}
  AND id = #{id}

UPDATE project_tasks
SET approve_request_id = #{approve_request_id},
    updated_at = CURRENT_TIMESTAMP
WHERE project_id = #{project_id}
  AND id = #{id}

UPDATE project_tasks
SET status = #{status, jdbcType=VARCHAR},
    completion_summary = #{completion_summary},
    updated_at = CURRENT_TIMESTAMP
WHERE project_id = #{project_id}
  AND id = #{id}
